     1→import { chromium, firefox, webkit } from '@playwright/test'
     2→import { steps, BASE_URL } from './steps'
     3→import { showOverlay, waitForAdvance } from './overlay'
     4→import { verify } from './verify'
     5→import type { DemoOptions } from './types'
     6→
     7→async function checkServer(
     8→  url: string,
     9→  label: string,
    10→  init?: RequestInit,
    11→): Promise<{ ok: boolean; detail: string }> {
    12→  try {
    13→    const res = await fetch(url, { signal: AbortSignal.timeout(5000), ...init })
    14→    if (!res.ok) {
    15→      return { ok: false, detail: `${label} responded with HTTP ${res.status}` }
    16→    }
    17→    return { ok: true, detail: '' }
    18→  } catch (err) {
    19→    const msg = err instanceof Error ? err.message : String(err)
    20→    return { ok: false, detail: `${label} at ${url} is not reachable: ${msg}` }
    21→  }
    22→}
    23→
    24→async function preflight(): Promise<void> {
    25→  const web = await checkServer(BASE_URL, 'Web dev server')
    26→  if (!web.ok) {
    27→    console.error('\n--- Demo preflight failed ---\n')
    28→    console.error(`  - ${web.detail}`)
    29→    console.error('\nStart the dev environment first:  make dev\n')
    30→    process.exit(1)
    31→  }
    32→
    33→  // Check the API through the Vite proxy with a minimal GraphQL introspection query
    34→  const api = await checkServer(`${BASE_URL}/graphql`, 'API server (via proxy)', {
    35→    method: 'POST',
    36→    headers: { 'Content-Type': 'application/json' },
    37→    body: JSON.stringify({ query: '{__typename}' }),
    38→  })
    39→  if (!api.ok) {
    40→    console.warn(`\n⚠ ${api.detail}`)
    41→    console.warn('  The demo will run but data-dependent steps may fail or show empty results.\n')
    42→  }
    43→}
    44→
    45→function parseArgs(): DemoOptions {
    46→  const args = process.argv.slice(2)
    47→  const opts: DemoOptions = {
    48→    mode: 'auto',
    49→    pauseMs: 3000,
    50→    startStep: 1,
    51→    browser: 'chromium',
    52→    headless: false,
    53→  }
    54→
    55→  for (const arg of args) {
    56→    if (arg === '--manual') {
    57→      opts.mode = 'manual'
    58→    } else if (arg === '--headless') {
    59→      opts.headless = true
    60→    } else if (arg.startsWith('--pause=')) {
    61→      opts.pauseMs = parseInt(arg.split('=')[1], 10)
    62→    } else if (arg.startsWith('--step=')) {
    63→      opts.startStep = parseInt(arg.split('=')[1], 10)
    64→    } else if (arg.startsWith('--browser=')) {
    65→      const b = arg.split('=')[1] as DemoOptions['browser']
    66→      if (['chromium', 'firefox', 'webkit'].includes(b)) {
    67→        opts.browser = b
    68→      }
    69→    }
    70→  }
    71→
    72→  return opts
    73→}
    74→
    75→async function main() {
    76→  const opts = parseArgs()
    77→
    78→  await preflight()
    79→
    80→  const launchers = { chromium, firefox, webkit }
    81→  const launcher = launchers[opts.browser]
    82→
    83→  if (opts.headless) {
    84→    console.log(`\n🧪 College Power Search Demo (headless smoke test)`)
    85→    console.log(`   Steps: ${steps.length}\n`)
    86→  } else {
    87→    console.log(`\n🎬 College Power Search Demo`)
    88→    console.log(
    89→      `   Mode: ${opts.mode === 'manual' ? 'manual (click to advance)' : `auto (${opts.pauseMs}ms pause)`}`,
    90→    )
    91→    console.log(`   Browser: ${opts.browser}`)
    92→    console.log(`   Steps: ${steps.length}\n`)
    93→  }
    94→
    95→  const browser = await launcher.launch({
    96→    headless: opts.headless,
    97→    slowMo: opts.headless ? 0 : 50,
    98→  })
    99→
   100→  const context = await browser.newContext({
   101→    viewport: { width: 1280, height: 800 },
   102→    baseURL: BASE_URL,
   103→  })
   104→  const page = await context.newPage()
   105→
   106→  const startIndex = Math.max(0, opts.startStep - 1)
   107→  let totalPassed = 0
   108→  let totalFailed = 0
   109→
   110→  try {
   111→    for (let i = startIndex; i < steps.length; i++) {
   112→      const step = steps[i]
   113→      console.log(`  [${i + 1}/${steps.length}] ${step.title}`)
   114→
   115→      // Run the step action
   116→      await step.action(page)
   117→
   118→      if (step.expect?.length) {
   119→        const result = await verify(page, step.expect)
   120→        totalPassed += result.passed
   121→        totalFailed += result.failed
   122→      }
   123→
   124→      if (!opts.headless) {
   125→        // Inject the overlay after the action (in case of navigation)
   126→        await showOverlay(page, {
   127→          stepIndex: i,
   128→          totalSteps: steps.length,
   129→          title: step.title,
   130→          description: step.description,
   131→          mode: opts.mode,
   132→          pauseMs: opts.pauseMs,
   133→        })
   134→
   135→        // Wait for advance
   136→        if (i < steps.length - 1) {
   137→          await waitForAdvance(page, opts.mode, opts.pauseMs)
   138→        } else {
   139→          // Last step — keep the browser open for the observer
   140→          console.log('\n✅ Demo complete. Close the browser to exit.\n')
   141→          await page.waitForEvent('close', { timeout: 0 }).catch(() => {})
   142→        }
   143→      }
   144→    }
   145→
   146→    if (opts.headless) {
   147→      console.log(`\nVerification: ${totalPassed} passed, ${totalFailed} failed`)
   148→      if (totalFailed > 0) {
   149→        process.exit(1)
   150→      }
   151→      console.log('\n✅ All demo steps passed.\n')
   152→    }
   153→  } catch (err) {
   154→    if (
   155→      !opts.headless &&
   156→      (err as Error).message?.includes('Target page, context or browser has been closed')
   157→    ) {
   158→      console.log('\n👋 Browser closed. Demo ended.\n')
   159→    } else {
   160→      throw err
   161→    }
   162→  } finally {
   163→    await browser.close().catch(() => {})
   164→  }
   165→}
   166→
   167→main().catch((err) => {
   168→  console.error('Demo failed:', err)
   169→  process.exit(1)
   170→})
